import Foundation

struct CategoryContent1 {
    static let aiBasics = CategoryData(
        id: "ai_basics", name: "What Is AI?", icon: "brain", colorName: "aiBlue",
        description: "Discover what artificial intelligence is and how it works",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 0,
        unlockRequirement: .none
    )

    static let lesson1 = LessonData(id: "ab_l1", title: "What is Artificial Intelligence?", description: "Learn the fundamentals of AI", categoryId: "ai_basics", questions: [
        Question(id: "ab1_q1", type: .multipleChoice, questionText: "What does 'AI' stand for?", options: ["Artificial Intelligence", "Automated Integration", "Advanced Interface", "Analytical Iteration"], correctAnswer: "Artificial Intelligence", explanation: "AI stands for Artificial Intelligence — the simulation of human intelligence by computer systems, pursued by organizations like Anthropic, Google DeepMind, and OpenAI."),
        Question(id: "ab1_q2", type: .trueFalse, questionText: "Today's AI systems, including Claude, Gemini, and GPT, can truly think and feel emotions just like humans.", options: ["True", "False"], correctAnswer: "False", explanation: "Current AI systems process data and recognize patterns but do not have consciousness or genuine emotions, regardless of how human-like their responses may seem."),
        Question(id: "ab1_q3", type: .multipleChoice, questionText: "Which of these is an example of AI in daily life?", options: ["A voice assistant like Siri or Alexa", "A website bookmark", "A digital alarm clock", "An online form"], correctAnswer: "A voice assistant like Siri or Alexa", explanation: "Voice assistants use natural language processing and machine learning to understand and respond to your voice, powered by AI models running on-device and in the cloud."),
        Question(id: "ab1_q4", type: .fillInBlank, questionText: "The goal of AI is to create machines that can perform tasks that typically require __________ intelligence.", options: ["human", "mechanical", "collective", "artificial"], correctAnswer: "human", explanation: "AI aims to replicate cognitive functions typically associated with human minds, such as learning, reasoning, and problem-solving."),
        Question(id: "ab1_q5", type: .multipleChoice, questionText: "Which field does AI NOT typically belong to?", options: ["Geology", "Computer Science", "Mathematics", "Linguistics"], correctAnswer: "Geology", explanation: "AI is an interdisciplinary field rooted in computer science, mathematics, linguistics, and philosophy, though it is now applied across nearly every industry."),
        Question(id: "ab1_q6", type: .trueFalse, questionText: "AI is a single technology rather than a collection of different approaches.", options: ["True", "False"], correctAnswer: "False", explanation: "AI is an umbrella term covering many technologies including machine learning, natural language processing, computer vision, robotics, and expert systems.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "ab_l2", title: "Machine Learning Fundamentals", description: "How machines learn from data", categoryId: "ai_basics", questions: [
        Question(id: "ab2_q1", type: .multipleChoice, questionText: "What is Machine Learning?", options: ["A subset of AI where systems learn from data", "A branch of robotics focused on movement", "A database management system", "A method of manually programming rules"], correctAnswer: "A subset of AI where systems learn from data", explanation: "Machine Learning is a branch of AI focused on building systems that learn from and make decisions based on data, forming the foundation of models like Claude, Gemini, and Llama."),
        Question(id: "ab2_q2", type: .fillInBlank, questionText: "In machine learning, the data used to teach a model is called __________ data.", options: ["training", "testing", "random", "output"], correctAnswer: "training", explanation: "Training data is the dataset used to teach a machine learning model to recognize patterns. For example, Meta AI used vast text corpora to train the Llama family of models."),
        Question(id: "ab2_q3", type: .trueFalse, questionText: "Machine Learning requires a programmer to write explicit rules for every possible scenario.", options: ["True", "False"], correctAnswer: "False", explanation: "ML learns patterns from data rather than being explicitly programmed. This is why models like Mistral and Claude can handle tasks their creators never manually coded for."),
        Question(id: "ab2_q4", type: .multipleChoice, questionText: "What does a machine learning model produce after training?", options: ["Predictions or classifications", "Exact copies of training data", "Optimized hardware configurations", "Formatted reports"], correctAnswer: "Predictions or classifications", explanation: "After training, ML models can make predictions or classify new, unseen data based on learned patterns — from medical diagnoses to content recommendations."),
        Question(id: "ab2_q5", type: .matchPairs, questionText: "Match each ML concept with its description:", matchPairs: [
            MatchPair(term: "Algorithm", definition: "Set of rules for learning"),
            MatchPair(term: "Dataset", definition: "Collection of data for training"),
            MatchPair(term: "Model", definition: "Learned representation of patterns"),
            MatchPair(term: "Feature", definition: "Individual measurable property")
        ], explanation: "These are the core building blocks of any machine learning system, whether used by Anthropic, Google DeepMind, or independent researchers."),
        Question(id: "ab2_q6", type: .multipleChoice, questionText: "Which is the best analogy for how ML works?", options: ["Learning from many examples, like a student studying", "Following a fixed set of rules precisely", "Looking up answers in an encyclopedia", "Memorizing every possible scenario"], correctAnswer: "Learning from many examples, like a student studying", explanation: "ML models learn by processing many examples, gradually improving their understanding, much like a student studying thousands of practice problems.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "ab_l3", title: "Neural Networks", description: "Computing systems inspired by the brain", categoryId: "ai_basics", questions: [
        Question(id: "ab3_q1", type: .multipleChoice, questionText: "Neural networks are inspired by:", options: ["The human brain", "Computer circuit boards", "Mathematical equations", "Telephone networks"], correctAnswer: "The human brain", explanation: "Artificial neural networks are loosely modeled on biological neural networks in the human brain, using layers of interconnected nodes to process information."),
        Question(id: "ab3_q2", type: .trueFalse, questionText: "A neural network is made up of layers of interconnected nodes.", options: ["True", "False"], correctAnswer: "True", explanation: "Neural networks consist of an input layer, hidden layers, and an output layer of interconnected nodes (neurons), forming the backbone of models from Anthropic, Google DeepMind, and Meta AI."),
        Question(id: "ab3_q3", type: .sortOrder, questionText: "Put these neural network layers in order from input to output:", options: ["Output Layer", "Hidden Layer 1", "Input Layer", "Hidden Layer 2"], correctAnswers: ["Input Layer", "Hidden Layer 1", "Hidden Layer 2", "Output Layer"], explanation: "Data flows from the input layer through hidden layers to produce results at the output layer, a structure used across all major AI models."),
        Question(id: "ab3_q4", type: .multipleChoice, questionText: "What do 'weights' in a neural network represent?", options: ["The strength of connections between neurons", "The number of training examples used", "The size of each layer", "The learning rate of the model"], correctAnswer: "The strength of connections between neurons", explanation: "Weights determine how much influence one neuron has on another. When we say a model has billions of parameters, those are primarily weights being adjusted during training."),
        Question(id: "ab3_q5", type: .fillInBlank, questionText: "A neural network with many hidden layers is called a __________ neural network.", options: ["deep", "wide", "flat", "simple"], correctAnswer: "deep", explanation: "Deep neural networks have multiple hidden layers, which is where the term 'deep learning' comes from — the foundation of modern AI breakthroughs."),
        Question(id: "ab3_q6", type: .multipleChoice, questionText: "What is the process of adjusting weights in a neural network called?", options: ["Training", "Installing", "Compiling", "Downloading"], correctAnswer: "Training", explanation: "Training is the process of feeding data through the network and adjusting weights to improve accuracy, often requiring powerful GPU clusters and weeks of computation.")
    ], order: 2, difficulty: .beginner)

    static let lesson4 = LessonData(id: "ab_l4", title: "Deep Learning", description: "The power of deep neural networks", categoryId: "ai_basics", questions: [
        Question(id: "ab4_q1", type: .multipleChoice, questionText: "Deep Learning is:", options: ["A subset of Machine Learning using deep neural networks", "A rule-based expert system approach", "A data visualization technique", "A method for cleaning datasets"], correctAnswer: "A subset of Machine Learning using deep neural networks", explanation: "Deep Learning uses neural networks with many layers to learn complex patterns from large amounts of data, powering breakthroughs from Google DeepMind's AlphaFold to Anthropic's Claude."),
        Question(id: "ab4_q2", type: .trueFalse, questionText: "Deep Learning typically requires large amounts of data to work well.", options: ["True", "False"], correctAnswer: "True", explanation: "Deep learning models generally need massive datasets to learn the complex patterns they're designed to capture, which is why companies invest heavily in data curation."),
        Question(id: "ab4_q3", type: .matchPairs, questionText: "Match each deep learning application to its domain:", matchPairs: [
            MatchPair(term: "Image Recognition", definition: "Identifying objects in photos"),
            MatchPair(term: "Speech Recognition", definition: "Converting voice to text"),
            MatchPair(term: "NLP", definition: "Understanding human language"),
            MatchPair(term: "Protein Folding", definition: "Predicting molecular structures")
        ], explanation: "Deep learning powers applications across many domains, from Google DeepMind's AlphaFold for protein structures to Meta AI's speech translation systems."),
        Question(id: "ab4_q4", type: .multipleChoice, questionText: "What hardware advancement helped enable modern deep learning?", options: ["GPUs (Graphics Processing Units)", "Solid-state drives (SSDs)", "High-bandwidth RAM modules", "Multi-core CPUs"], correctAnswer: "GPUs (Graphics Processing Units)", explanation: "GPUs from companies like NVIDIA can perform many calculations in parallel, making them essential for training deep neural networks used by every major AI lab."),
        Question(id: "ab4_q5", type: .fillInBlank, questionText: "Deep learning excels at finding __________ in data that are too complex for humans to program manually.", options: ["patterns", "errors", "files", "emails"], correctAnswer: "patterns", explanation: "Deep learning automatically discovers intricate patterns and representations in raw data, enabling everything from language understanding to drug discovery."),
        Question(id: "ab4_q6", type: .scenarioJudgment, questionText: "A company wants to automatically detect defective products on an assembly line using cameras. Should they consider deep learning?", options: ["Yes, this is ideal", "No, not suitable", "It depends"], correctAnswer: "Yes, this is ideal", explanation: "Computer vision powered by deep learning excels at visual inspection tasks and is widely deployed in manufacturing by companies worldwide.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "ab_l5", title: "Training Data & Bias", description: "Why data quality matters", categoryId: "ai_basics", questions: [
        Question(id: "ab5_q1", type: .multipleChoice, questionText: "Why is training data important for AI?", options: ["It determines what the model learns", "It defines the model's architecture", "It determines the programming language used", "It sets the model's processing speed"], correctAnswer: "It determines what the model learns", explanation: "The quality and content of training data directly shapes what an AI model can and cannot do. This is true for every model, from open-source Llama to proprietary systems like Claude and Gemini."),
        Question(id: "ab5_q2", type: .trueFalse, questionText: "If training data contains biases, the AI model will likely also be biased.", options: ["True", "False"], correctAnswer: "True", explanation: "AI models learn from their training data — if the data is biased, the model will reproduce those biases. This is a major concern addressed by AI safety teams at Anthropic, Google DeepMind, and other labs."),
        Question(id: "ab5_q3", type: .scenarioJudgment, questionText: "A facial recognition system was trained mostly on photos of light-skinned people. It performs poorly on darker-skinned individuals. Is this a data problem?", options: ["Yes, clearly", "No, it's fine", "It depends"], correctAnswer: "Yes, clearly", explanation: "This is a well-documented example of training data bias. Research by Joy Buolamwini and others showed that many commercial AI systems had significantly higher error rates for darker-skinned faces."),
        Question(id: "ab5_q4", type: .multipleChoice, questionText: "What is 'labeled data'?", options: ["Data with correct answers attached", "Data that has been cleaned and formatted", "Data stored in a structured database", "Data that has been compressed for storage"], correctAnswer: "Data with correct answers attached", explanation: "Labeled data includes both the input and the correct output, used in supervised learning. Human annotators play a crucial role in creating high-quality labeled datasets."),
        Question(id: "ab5_q5", type: .fillInBlank, questionText: "The phrase 'garbage in, garbage out' means that poor quality __________ leads to poor AI results.", options: ["data", "code", "hardware", "electricity"], correctAnswer: "data", explanation: "No matter how sophisticated a model's architecture is, it can only be as good as the data it is trained on. Data quality is a top priority for every AI lab."),
        Question(id: "ab5_q6", type: .multipleChoice, questionText: "Which is NOT a way to reduce bias in training data?", options: ["Using less data overall", "Ensuring diverse representation", "Auditing data for imbalances", "Collecting data from varied sources"], correctAnswer: "Using less data overall", explanation: "Simply using less data does not fix bias — you need diverse, representative, and carefully curated datasets, along with systematic auditing and testing across demographic groups.")
    ], order: 4, difficulty: .intermediate)

    static let lesson6 = LessonData(id: "ab_l6", title: "Types of AI: Narrow vs General", description: "Understanding AI's current limits", categoryId: "ai_basics", questions: [
        Question(id: "ab6_q1", type: .multipleChoice, questionText: "What type of AI exists today?", options: ["Narrow AI (ANI)", "General AI (AGI)", "Super AI (ASI)", "Conscious AI"], correctAnswer: "Narrow AI (ANI)", explanation: "All current AI systems — Claude, Gemini, GPT, Llama — are forms of Narrow AI. While they can handle many tasks, true General AI that matches all human cognitive abilities does not yet exist."),
        Question(id: "ab6_q2", type: .trueFalse, questionText: "A chess-playing AI can also write poetry equally well without additional training.", options: ["True", "False"], correctAnswer: "False", explanation: "Traditional narrow AI systems are specialized. However, modern large language models blur this line by handling many different tasks, though they still have significant limitations."),
        Question(id: "ab6_q3", type: .matchPairs, questionText: "Match each AI type to its description:", matchPairs: [
            MatchPair(term: "Narrow AI", definition: "Excels at specific tasks"),
            MatchPair(term: "General AI", definition: "Hypothetical human-level intelligence"),
            MatchPair(term: "Super AI", definition: "Theoretical beyond-human intelligence"),
            MatchPair(term: "Foundation Model", definition: "Versatile base model for many tasks")
        ], explanation: "Foundation models like Claude and Gemini are versatile narrow AI systems, but the debate about how close they are to general intelligence continues across the industry."),
        Question(id: "ab6_q4", type: .multipleChoice, questionText: "Which is an example of Narrow AI?", options: ["A spam email filter", "A general-purpose reasoning system", "An AI that understands all human emotions", "A system that can learn any new task instantly"], correctAnswer: "A spam email filter", explanation: "A spam filter is a classic example of Narrow AI — it does one specific task (classify emails) very well. Even advanced models like Claude are considered narrow AI, just with broader capabilities."),
        Question(id: "ab6_q5", type: .scenarioJudgment, questionText: "A startup claims their product has achieved 'AGI' (Artificial General Intelligence). Should you be skeptical?", options: ["Yes, be skeptical", "No, trust them", "It depends"], correctAnswer: "Yes, be skeptical", explanation: "AGI does not exist yet. Leading researchers at Anthropic, Google DeepMind, and other labs agree that true AGI remains an unsolved challenge. Claims of achieving AGI are almost certainly marketing hype."),
        Question(id: "ab6_q6", type: .fillInBlank, questionText: "Google DeepMind's AlphaGo, which beat the world champion in Go, is an example of __________ AI.", options: ["narrow", "general", "super", "conscious"], correctAnswer: "narrow", explanation: "AlphaGo is narrow AI — it mastered Go but cannot do other tasks like hold a conversation or write code. It was a landmark achievement for Google DeepMind but remains specialized.")
    ], order: 5, difficulty: .intermediate)
}
